// Parse Slack slash command payload (form-encoded)
const body = $input.first().json.body;

const command = body.command || '/ai';
const text = (body.text || '').trim();
const userId = body.user_id || '';
const userName = body.user_name || 'unknown';
const channelId = body.channel_id || '';
const channelName = body.channel_name || '';
const responseUrl = body.response_url || '';

// Route based on command
let agent = 'general';
if (command === '/ai-status') agent = 'status';
else if (command === '/ai-draw') agent = 'draw';
else if (command === '/ai-diagnose') agent = 'diagnose';
else if (text.toLowerCase().startsWith('kevin')) agent = 'kevin';
else if (text.toLowerCase().startsWith('jason')) agent = 'jason';
else if (text.toLowerCase().startsWith('scaachi')) agent = 'scaachi';
else if (text.toLowerCase().startsWith('christian')) agent = 'christian';
else if (text.toLowerCase().startsWith('chidi')) agent = 'chidi';

return [{
  json: {
    command,
    text,
    userId,
    userName,
    channelId,
    channelName,
    responseUrl,
    agent,
    receivedAt: new Date().toISOString()
  }
}];
